// ============================================================================
// PARSE MILO RESPONSE & EXTRACT COMMANDS
// ============================================================================

const miloOutput = $input.first().json;
let responseText = '';

if (typeof miloOutput.output === 'string') {
  responseText = miloOutput.output;
} else if (miloOutput.output && typeof miloOutput.output === 'object') {
  responseText = JSON.stringify(miloOutput.output);
} else {
  responseText = miloOutput.text || '';
}

// Extract COMMAND blocks
const commandPattern = /COMMAND:\s*([A-Z_]+)[\s\S]*?REASON:\s*([^\n]+)[\s\S]*?PAYLOAD:\s*(\{[\s\S]*?\})/g;
const commands = [];

let match;
while ((match = commandPattern.exec(responseText)) !== null) {
  const [_, command, reason, payloadStr] = match;
  try {
    const payload = JSON.parse(payloadStr);
    commands.push({ command, reason, payload });
  } catch (e) {
    console.error('Failed to parse command payload:', e);
  }
}

const taskContext = $('Prepare Creative Context').item.json.task_context;

return [{
  json: {
    agent_response: {
      message: responseText.split('COMMAND:')[0].trim(),
      agent_used: 'milo',
      commands,
      raw_response: responseText
    },
    task_context: taskContext
  }
}];

// ============================================================================
// EXECUTE WRITE-BACK COMMANDS TO SUPABASE
// ============================================================================

const { commands } = $input.item.json.agent_response;
const { project_id, task_id } = $input.item.json.task_context;

// TODO: Implémenter vrais appels Supabase
// Pour l'instant, log les commandes

for (const cmd of commands) {
  console.log(`Executing command: ${cmd.command}`);
  console.log(`Reason: ${cmd.reason}`);
  console.log(`Payload:`, cmd.payload);

  // En production:
  // switch (cmd.command) {
  //   case 'ADD_FILE':
  //     await supabase.from('project_files').insert({ project_id, ...cmd.payload });
  //     break;
  //   case 'UPDATE_TASK_STATUS':
  //     await supabase.from('tasks').update({ status: cmd.payload.status }).eq('id', cmd.payload.task_id);
  //     break;
  //   case 'MEMORY_WRITE':
  //     await supabase.from('project_memory').insert({ project_id, agent_id: 'milo', ...cmd.payload });
  //     break;
  // }
}

return [{
  json: {
    success: true,
    commands_executed: commands.length,
    agent_response: $input.item.json.agent_response,
    project_id,
    task_id
  }
}];
